INSERT INTO [T_Episodes] ([Id],[Title],[AlbumId],[SequenceNumber],[IsVisible],[AudioUrl],[DurationInSecond],[Subtitle],[SubtitleType],[CreateTime],[IsDeleted]) VALUES (N'D9D1AF98-D817-45D5-8397-8266A868C83A',N'Family Relationships - Randall&#039;s ESL Cyber Listening Lab',N'02AA1FDD-E8D9-4A63-B96B-E108C3F2D478',13,1,N'mp3\fam2.mp3__=1.mp3',NULL,N'General Listening Quiz &#8220;Family Relationships&#8221; (adsbygoogle = window.adsbygoogle || []).push({}); See Listening Script Back to Easy Quizzes Language Games .lesson-links { display: flex; justify-content: space-between; padding: 0px 0 0px 0; } .lesson-link { color: #174973; text-decoration: none; font-weight: 500; transition: color 0.2s; } .lesson-link:hover { color: #005a87; text-decoration: underline; } ◄ Previous Activity Next Activity ► .spacedlist li { margin-bottom: 10px; } ul.vocabulary li { margin-bottom: 10px; } /* Add space above nested lists */ .spacedlist li ul, .spacedlist li ol, ul.vocabulary li ul, ul.vocabulary li ol { margin-top: 10px; } .table-container { max-width: 1200px; margin: 0 auto; overflow-x: auto; } .overview-table { width: 100%; border-collapse: collapse; border: 1px solid #666; box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1); } .overview-table th, .overview-table td { padding: 12px 15px; text-align: center; border: 1px solid #666; } .overview-table th { background: #f0f6fb; font-weight: bold; color: #333; } /* Mobile */ @media (max-width: 600px) { .overview-table { box-shadow: none; border: none; } .overview-table thead { display: none; } .overview-table tr { display: block; margin-bottom: 15px; border: 1px solid #666; } .overview-table td { display: block; text-align: right; padding: 10px 15px; position: relative; border: none; border-top: 1px solid #999; } .overview-table td:first-child { border-top: none; } .overview-table td::before { content: attr(data-label); position: absolute; left: 15px; font-weight: bold; color: #333; text-align: left; } } Level Topic Speakers Length Easy Families Man &#8211; Man 01:10 Pre-Listening Exercise What five questions could you ask someone about his or her family (e.g., What does your father do?)? Agree or Disagree? Let’s Spark Some Conversation! Do you agree or disagree with these statements. Talk together and share your opinions. Family members should always support each other. It’s important to talk to your family every day. Brothers and sisters always fight when they’re young. Parents should be their children’s best friends. Grandparents give the best advice. It’s easier to be honest with family than with friends. Family problems should stay private. You can be close to your family even if you live far away. It’s okay to disagree with your parents. Spending time with family is more important than making money. Idioms &#8220;get under someone&#8217;s skin&#8221; = annoy or bother someone &#8220; My brother gets under my skin when he enters my room without knocking .&#8221; &#8220;stay-at-home mom&#8221; = a mother who doesn&#8217;t have a job outside the home &#8220; My sister finds satisfaction in being a stay-at-home mom .&#8221; Listening Exercise Listen to the recording and answer the questions. ( See transcript ) https://esllab.b-cdn.net/audio/mp3/fam2.mp3 /* Button styling */ .audio-speed-btn { font-weight: bold; font-size: 16px; color: #000; margin-right: 6px; cursor: pointer; transition: all 0.2s ease; } .audio-speed-btn:hover { background-color: #5dade2; color: #fff; } .audio-speed-btn.active { background-color: #5dade2; color: #fff; } /* 📱 Mobile adjustments */ @media (max-width: 768px) { .audio-speed-btn { font-size: 12px; /* slightly smaller on tablets */ } } @media (max-width: 480px) { .audio-speed-btn { font-size: 12px; /* smaller on phones */ } } document.addEventListener("DOMContentLoaded", function() { const audio = document.querySelector("audio"); if (!audio) return; // Create wrapper for buttons const wrapper = document.createElement("div"); wrapper.className = "uk-margin-small-top"; // ✅ spacing using Yootheme Pro class wrapper.style.display = "flex"; wrapper.style.alignItems = "center"; // Label const label = document.createElement("span"); label.innerText = "Speed:"; label.style.fontWeight = "bold"; label.style.marginRight = "8px"; wrapper.appendChild(label); // Speed buttons const speeds = [0.75, 0.85, 1, 1.25]; speeds.forEach(speed => { const btn = document.createElement("button"); btn.className = "audio-speed-btn"; btn.innerText = speed + "x"; btn.onclick = () => { audio.playbackRate = speed; wrapper.querySelectorAll(".audio-speed-btn").forEach(b => b.classList.remove("active")); btn.classList.add("active"); }; wrapper.appendChild(btn); }); // Skip back 5s button const skipBtn = document.createElement("button"); skipBtn.className = "audio-speed-btn"; skipBtn.innerText = "⏪ Back 5s"; skipBtn.title = "Go back 5 seconds"; // tooltip for clarity skipBtn.onclick = () => { audio.currentTime = Math.max(0, audio.currentTime - 5); }; wrapper.appendChild(skipBtn); // Insert buttons after audio player audio.insertAdjacentElement("afterend", wrapper); // Set default speed 1x audio.playbackRate = 1; const defaultBtn = Array.from(wrapper.querySelectorAll(".audio-speed-btn")) .find(b => parseFloat(b.innerText) === 1); if (defaultBtn) defaultBtn.classList.add("active"); }); Family Relationships Where is Pancho from? How many brothers and sisters does Pancho have? What is his father&#8217;s job? What does his mother do? Who works at the family business? Great Job! Nice try! medianet_width = "728"; medianet_height = "90"; medianet_crid = "842863434"; medianet_versionId = "3111299"; Vocabulary and Sample Sentences Here are some words that appear in the recording: support (verb) : give help or assistance &#8211; Does your family support you with your college expenses? run (verb) : be in charge of &#8211; My brother is going to run our business when my father retires. kind (noun) : type &#8211; What kind of work does your mother do? mainly (adverb) : for the most part &#8211; We mainly spend time at home and watch TV in the evenings. Vocabulary Practice Do the vocabulary quizzes with the words from the conversation for more practice: Mixed-Up Sentence Multiple-Choice Questions Sentence and Vocabulary Matching Gap-fill Exercise Post-Listening Exercise Ask a partner five questions about his or her family. Then introduce your partner to another student using the information you learned about that person. Who are you closest to in your family: mother, father, brother, sister, or another relative? Why? Keep Learning With Related Language Activities 🎧 Related Listening Activity ▶️ Related Video Lesson ✅ Next Level Challenge 📝 Self-Study Guide ⭐ Randall&#8217;s Favorites .lesson-links { display: flex; justify-content: space-between; padding: 0px 0 0px 0; } .lesson-link { color: #174973; text-decoration: none; font-weight: 500; transition: color 0.2s; } .lesson-link:hover { color: #005a87; text-decoration: underline; } ◄ Previous Activity Next Activity ► See Listening Script Back to Easy Quizzes Language Games Try More Free Listening at DailyESL.com Follow Randall: (adsbygoogle = window.adsbygoogle || []).push({}); Study Guide Academic English Listening Basic English Quizzes Easy Listening Intermediate Listening Difficult Listening English Grammar Lessons Interviews English Idioms English Culture Videos ESL Vocabulary Quizzes medianet_width = "300"; medianet_height = "600"; medianet_crid = "621252724"; medianet_versionId = "3111299"; (adsbygoogle = window.adsbygoogle || []).push({});',N'text',@Now,0); GO
